# Patterns that signal an explicit context switch
TRANSITION_PATTERNS = [
    re.compile(r"(?:ok|okay|alright|now|so)\s+(?:about|regarding|for|let me|switching to)\b", re.I),
    re.compile(r"(?:different topic|change of subject|moving on|on another note)\b", re.I),
    re.compile(r"(?:back to|returning to|let's talk about)\b", re.I),
]

META_KEY = "self_state_learning"


class SelfStateDetector:
    """Detects and learns the user's active self-state."""

    def __init__(self, storage: Optional[BaseStorage] = None):
        self.storage = storage
        self._learned: Dict[str, Dict[str, int]] = {}
        self._custom_states: Dict[str, Set[str]] = {}
        if storage:
            self._load_learning_data()

    # -----------------------------------------------------------------
    # Persistence
    # -----------------------------------------------------------------

    def _load_learning_data(self) -> None:
        if not self.storage:
            return
        raw = self.storage.get_meta(META_KEY, "{}")
        data = safe_json_loads(raw, {})
        self._learned = data.get("entity_states", {})
        self._custom_states = {
            k: set(v) for k, v in data.get("custom_states", {}).items()
        }

    def _save_learning_data(self) -> None:
        if not self.storage:
            return
        data = {
            "entity_states": self._learned,
            "custom_states": {k: sorted(v) for k, v in self._custom_states.items()},
        }
        self.storage.set_meta(META_KEY, safe_json_dumps(data))

    # -----------------------------------------------------------------
    # Detection
    # -----------------------------------------------------------------

    def detect(self, text: str, entity_names: Optional[List[str]] = None) -> str:
        """Detect the active self-state from text and extracted entities.

        Priority:
          1. Seed vocabulary scoring
          2. Learned entity → state co-occurrences
          3. Custom (discovered) states
          4. Default "general"
        """
        t = text.lower()
        tokens = set(re.findall(r"[a-z0-9_\-]+", t))

        has_transition = any(p.search(text) for p in TRANSITION_PATTERNS)

        # Score each seed state
        state_scores: Dict[str, float] = {}
        for state, vocab in SEED_STATES.items():
            hits = len(tokens & vocab)
            if hits > 0:
                state_scores[state] = float(hits)

        # Score custom (discovered) states
        for state, vocab in self._custom_states.items():
            hits = len(tokens & vocab)
            if hits > 0:
                state_scores[state] = state_scores.get(state, 0.0) + float(hits)

        # Score from learned entity → state co-occurrences
        if entity_names:
            for ename in entity_names:
                low = ename.lower()
                if low in self._learned:
                    for state, count in self._learned[low].items():
                        state_scores[state] = state_scores.get(state, 0.0) + count * 0.3

        if not state_scores:
            return "general"

        best_state = max(state_scores, key=state_scores.get)  # type: ignore[arg-type]
        best_score = state_scores[best_state]

        if best_score < 1.0 and not has_transition:
            return "general"

        return best_state

    # -----------------------------------------------------------------
    # Learning
    # -----------------------------------------------------------------

    def learn(self, entity_names: List[str], detected_state: str) -> None:
        """Record that these entities co-occurred with this state."""
        if detected_state == "general" or not entity_names:
            return
        for ename in entity_names:
            low = ename.lower()
            if low not in self._learned:
                self._learned[low] = {}
            self._learned[low][detected_state] = (
                self._learned[low].get(detected_state, 0) + 1
            )
        self._save_learning_data()

    def discover_state(self, entity_names: List[str]) -> Optional[str]:
        """Create a new state if unmatched entities cluster enough.

        If 3+ entities appear together without matching any known state,
        create a new custom state named after the dominant entity.
        """
        unmatched: List[str] = []
        for ename in entity_names:
            low = ename.lower()
            in_seed = any(low in vocab for vocab in SEED_STATES.values())
            in_custom = any(low in vocab for vocab in self._custom_states.values())
            if not in_seed and not in_custom:
                unmatched.append(low)

        if len(unmatched) < 3:
            return None

        # Skip if these entities already map strongly to a known state
        for ename in unmatched:
            if ename in self._learned:
                if max(self._learned[ename].values(), default=0) >= 3:
                    return None

        new_state = f"context_{unmatched[0]}"
        self._custom_states[new_state] = set(unmatched)
        self._save_learning_data()
        return new_state

"""
Semantic Gravity Memory — Abstract Embedder Interface
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from typing import List


class BaseEmbedder(ABC):
    """Contract for all embedding providers."""

    @abstractmethod
    def embed(self, text: str) -> List[float]:
        """Generate an embedding vector for the given text."""
        ...

    def embed_batch(self, texts: List[str]) -> List[List[float]]:
        """Generate embeddings for multiple texts. Default: sequential calls."""
        return [self.embed(t) for t in texts]

    @abstractmethod
    def dimension(self) -> int:
        """Return the embedding dimension, or 0 if unknown until first call."""
        ...

"""
Semantic Gravity Memory — Abstract Storage Interface

Every storage backend (SQLite, Postgres, in-memory) must implement this.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Any, Dict, List, Optional, Tuple

from semantic_gravity_memory.models import (
    Activation,
    AntibodyMemory,
    Contradiction,
    Crystal,
    Entity,
    Event,
    ProspectiveMemory,
    Relation,
    Schema,
)


class BaseStorage(ABC):
    """Abstract contract for all memory storage backends."""

    # -- Events ---------------------------------------------------------------

    @abstractmethod
    def insert_event(self, event: Event) -> int:
        """Store an event, return its assigned id."""
        ...

    @abstractmethod
    def get_event(self, event_id: int) -> Optional[Event]:
        ...

    @abstractmethod
    def recent_events(self, limit: int = 50) -> List[Event]:
        """Most recent events, newest first."""
        ...

    # -- Entities -------------------------------------------------------------

    @abstractmethod
    def upsert_entity(self, entity: Entity) -> int:
        """Insert or update by name. Returns entity id."""
        ...

    @abstractmethod
    def get_entity(self, entity_id: int) -> Optional[Entity]:
        ...

    @abstractmethod
    def get_entity_by_name(self, name: str) -> Optional[Entity]:
        ...

    @abstractmethod
    def top_entities(self, limit: int = 50) -> List[Entity]:
        """Entities sorted by salience descending."""
        ...

    # -- Crystals -------------------------------------------------------------

    @abstractmethod
    def insert_crystal(self, crystal: Crystal) -> int:
        ...

    @abstractmethod
    def update_crystal(self, crystal: Crystal) -> None:
        """Update an existing crystal (must have a valid id)."""
        ...

    @abstractmethod
    def get_crystal(self, crystal_id: int) -> Optional[Crystal]:
        ...

    @abstractmethod
    def all_crystals(self) -> List[Crystal]:
        ...

    @abstractmethod
    def recent_crystals(self, limit: int = 50) -> List[Crystal]:
        """Most recent crystals, newest first."""
        ...

    # -- Gravitational retrieval ----------------------------------------------

    @abstractmethod
    def crystals_by_entity_ids(self, entity_ids: List[int], limit: int = 50) -> List[Crystal]:
        """Active crystals connected to any of the given entity IDs via relations."""
        ...

    @abstractmethod
    def top_crystals_by_mass(self, limit: int = 50) -> List[Crystal]:
        """Heaviest active crystals by pre-computed gravitational mass."""
        ...

    @abstractmethod
    def update_crystal_masses(self, mass_map: Dict[int, float]) -> None:
        """Batch-update gravitational mass for crystals. {crystal_id: mass}."""
        ...

    @abstractmethod
    def entity_names_and_ids(self) -> List[Tuple[int, str]]:
        """All (entity_id, entity_name) pairs, ordered by salience desc."""
        ...

    # -- Relations ------------------------------------------------------------

    @abstractmethod
    def insert_relation(self, relation: Relation) -> int:
        ...

    @abstractmethod
    def relations_from(self, source_type: str, source_id: int) -> List[Relation]:
        ...

    @abstractmethod
    def relations_to(self, target_type: str, target_id: int) -> List[Relation]:
        ...

    @abstractmethod
    def all_relations(self) -> List[Relation]:
        ...

    # -- Contradictions -------------------------------------------------------

    @abstractmethod
    def insert_contradiction(self, contradiction: Contradiction) -> int:
        ...

    @abstractmethod
    def update_contradiction(self, contradiction: Contradiction) -> None:
        ...

    @abstractmethod
    def open_contradictions(self) -> List[Contradiction]:
        """Contradictions with resolution_state == 'open'."""
        ...

    @abstractmethod
    def all_contradictions(self) -> List[Contradiction]:
        ...

    # -- Activations ----------------------------------------------------------

    @abstractmethod
    def insert_activation(self, activation: Activation) -> int:
        ...

    @abstractmethod
    def recent_activations(self, limit: int = 50) -> List[Activation]:
        ...

    # -- Prospective Memory ---------------------------------------------------

    @abstractmethod
    def insert_prospective(self, pm: ProspectiveMemory) -> int:
        ...

    @abstractmethod
    def active_prospective_memories(self) -> List[ProspectiveMemory]:
        """Unfired, non-expired prospective memories."""
        ...

    @abstractmethod
    def fire_prospective(self, pm_id: int, fired_ts: str) -> None:
        ...

    # -- Schemas --------------------------------------------------------------

    @abstractmethod
    def insert_schema(self, schema: Schema) -> int:
        ...

    @abstractmethod
    def update_schema(self, schema: Schema) -> None:
        ...

    @abstractmethod
    def all_schemas(self) -> List[Schema]:
        ...

    # -- Antibodies -----------------------------------------------------------

    @abstractmethod
    def insert_antibody(self, antibody: AntibodyMemory) -> int:
        ...

    @abstractmethod
    def active_antibodies(self) -> List[AntibodyMemory]:
        """Antibodies where active == True."""
        ...

    # -- Meta -----------------------------------------------------------------

    @abstractmethod
    def set_meta(self, key: str, value: str) -> None:
        ...

    @abstractmethod
    def get_meta(self, key: str, default: str = "") -> str:
        ...

    # -- Export ---------------------------------------------------------------

    @abstractmethod
    def export_all(self) -> Dict[str, Any]:
        """Full dump of all tables as a dict (JSON-serializable)."""
        ...

    # -- Lifecycle ------------------------------------------------------------

    @abstractmethod
    def close(self) -> None:
        ...

    def __enter__(self):
        return self

    def __exit__(self, *args):
        self.close()

/**
