/* === Second Brain — 3D UI === */
* { margin: 0; padding: 0; box-sizing: border-box; }

:root {
  --bg: #06060c;
  --surface: #0c0c14;
  --surface2: #10101a;
  --border: #1a1a2e;
  --text: #e0e0e8;
  --text-dim: #7a7a90;
  --accent: #4488ff;
  --accent-glow: #4488ff40;
  --gold: #ffaa33;
  --green: #44ff88;
  --red: #ff4466;
  --purple: #aa55ff;
  --font: 'SF Mono', 'Fira Code', 'Consolas', monospace;
}

html, body {
  width: 100%; height: 100%;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  font-size: 13px;
}

/* Top bar */
#topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 20px;
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  height: 52px;
  z-index: 10;
}
#topbar h1 {
  font-size: 16px;
  font-weight: 600;
  letter-spacing: 0.5px;
  color: #fff;
}
.tagline {
  font-size: 11px;
  color: var(--text-dim);
  margin-left: 14px;
}
.topbar-left { display: flex; align-items: baseline; gap: 8px; }
.topbar-right { display: flex; align-items: center; gap: 12px; }
.topbar-right label {
  display: flex; align-items: center; gap: 6px;
  font-size: 11px; color: var(--text-dim);
}
.topbar-right select {
  background: var(--surface2);
  color: var(--text);
  border: 1px solid var(--border);
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 11px;
  font-family: var(--font);
  min-width: 140px;
}
.topbar-right button, #chat-buttons button {
  background: var(--surface2);
  color: var(--text);
  border: 1px solid var(--border);
  padding: 5px 14px;
  border-radius: 4px;
  cursor: pointer;
  font-family: var(--font);
  font-size: 12px;
  transition: background 0.15s, border-color 0.15s;
}
.topbar-right button:hover, #chat-buttons button:hover {
  background: var(--border);
  border-color: var(--accent);
}

/* Main layout */
#app {
  display: flex;
  height: calc(100vh - 52px);
}

/* 3D viewport */
#viewport {
  flex: 1;
  position: relative;
  overflow: hidden;
}
#brain-canvas {
  width: 100%;
  height: 100%;
  display: block;
}

/* Tooltip */
#tooltip {
  position: absolute;
  pointer-events: none;
  background: #0d0d18ee;
  border: 1px solid var(--accent);
  border-radius: 6px;
  padding: 10px 14px;
  font-size: 12px;
  max-width: 320px;
  line-height: 1.5;
  box-shadow: 0 4px 20px #0008;
  z-index: 20;
}
#tooltip .tt-title {
  font-weight: 600;
  color: #fff;
  margin-bottom: 4px;
}
#tooltip .tt-meta {
  color: var(--text-dim);
  font-size: 11px;
}
.hidden { display: none !important; }

/* Status overlay */
#status-overlay {
  position: absolute;
  bottom: 16px;
  left: 16px;
  font-size: 11px;
  color: var(--text-dim);
  pointer-events: none;
}

/* Node count */
#node-count {
  position: absolute;
  top: 12px;
  left: 16px;
  font-size: 11px;
  color: var(--text-dim);
  pointer-events: none;
}

/* Right panel */
#panel {
  width: 380px;
  min-width: 300px;
  background: var(--surface);
  border-left: 1px solid var(--border);
  display: flex;
  flex-direction: column;
